     3→
     4→interface AxisScoreBarProps {
     5→  label: string;
     6→  score: number;
     7→  blockingGap?: boolean;
     8→  className?: string;
     9→}
    10→
    11→function getBarColor(score: number): string {
    12→  if (score >= 70) return "bg-emerald-500";
    13→  if (score >= 50) return "bg-amber-500";
    14→  if (score >= 30) return "bg-orange-500";
    15→  return "bg-red-500";
    16→}
    17→
    18→export function AxisScoreBar({ label, score, blockingGap, className }: AxisScoreBarProps) {
    19→  return (
    20→    <div className={cn("flex items-center gap-3", className)}>
    21→      <span className="text-xs text-gray-400 uppercase tracking-wider font-medium w-32 shrink-0 truncate">
    22→        {label}
    23→      </span>
    24→      <div className="flex-1 h-2 bg-[#3A3D45] rounded-full overflow-hidden">
    25→        <div
    26→          className={cn("h-full rounded-full transition-all duration-700 ease-out", getBarColor(score))}
    27→          style={{ width: `${score}%` }}
    28→        />
    29→      </div>
    30→      <span className={cn(
    31→        "text-sm font-mono w-10 text-right tabular-nums",
    32→        score >= 70 ? "text-white" : "text-gray-400"
    33→      )}>
    34→        {score}
    35→      </span>
    36→      {blockingGap && (
    37→        <span title="Blocking gap"><AlertTriangle className="w-4 h-4 text-red-400 shrink-0" /></span>
    38→      )}
    39→    </div>
    40→  );
    41→}
