     1→/**
     2→ * K3RN.LABS — Logique de décision recommandée
     3→ * Source de vérité : Contrat Canonique Analyse Idée v1.1, Section 5.1
     4→ *
     5→ * Ordre de priorité strict :
     6→ * 1. KILL (la plus restrictive)
     7→ * 2. PARK
     8→ * 3. EXPLORE
     9→ * 4. GO (la moins restrictive)
    10→ */
    11→
    12→import { DECISION_THRESHOLDS, CRITICAL_AXES, type AnalysisAxis } from './constants';
    13→import type { AnalysisAxes } from './types';
    14→
    15→type Decision = 'GO' | 'EXPLORE' | 'PARK' | 'KILL';
    16→type ConfidenceLevel = 'LOW' | 'MEDIUM' | 'HIGH';
    17→
    18→interface DecisionResult {
    19→  recommendation: Decision;
    20→  reasons: string[];
    21→}
    22→
    23→/**
    24→ * Détermine la décision recommandée selon les règles canoniques.
    25→ *
    26→ * Règle 1 — KILL : score < 30 OU blocking_gap HIGH OU problem < 20
    27→ * Règle 2 — PARK : score [30,50[ ET aucun blocking_gap HIGH ET axes critiques >= 25
    28→ * Règle 3 — EXPLORE : score [50,70[ OU (score >= 70 ET confidence LOW)
    29→ * Règle 4 — GO : score >= 70 ET confidence >= MEDIUM ET aucun blocking_gap ET axes critiques >= 50
    30→ *
    31→ * En cas de conflit, la règle la plus restrictive prévaut.
    32→ */
    33→export function determineDecision(
    34→  globalScore: number,
    35→  analysis: AnalysisAxes,
    36→  confidenceLevel: ConfidenceLevel
    37→): DecisionResult {
    38→  // ─── Règle 1 : KILL ──────────────────────────────────────────
    39→  const killReasons: string[] = [];
    40→
    41→  if (globalScore < DECISION_THRESHOLDS.KILL_SCORE) {
    42→    killReasons.push(
    43→      `Score global (${globalScore}) < ${DECISION_THRESHOLDS.KILL_SCORE}`
    44→    );
    45→  }
    46→
    47→  // Vérifier blocking_gap HIGH (au moins 1 axe avec blocking_gap = true)
    48→  const blockingAxes = getBlockingGapAxes(analysis);
    49→  if (blockingAxes.length > 0) {
    50→    killReasons.push(
    51→      `Blocking gap détecté sur : ${blockingAxes.join(', ')}`
    52→    );
    53→  }
    54→
    55→  if (analysis.problem.score < DECISION_THRESHOLDS.KILL_PROBLEM_MIN) {
    56→    killReasons.push(
    57→      `Score Problème (${analysis.problem.score}) < ${DECISION_THRESHOLDS.KILL_PROBLEM_MIN}`
    58→    );
    59→  }
    60→
    61→  if (killReasons.length > 0) {
    62→    return { recommendation: 'KILL', reasons: killReasons };
    63→  }
    64→
    65→  // ─── Règle 2 : PARK ──────────────────────────────────────────
    66→  if (
    67→    globalScore >= DECISION_THRESHOLDS.PARK_MIN &&
    68→    globalScore < DECISION_THRESHOLDS.PARK_MAX
    69→  ) {
    70→    // Vérifier aucun axe critique < 25
    71→    const weakCriticalAxes = getCriticalAxesBelowThreshold(
    72→      analysis,
    73→      DECISION_THRESHOLDS.PARK_CRITICAL_MIN
    74→    );
    75→
    76→    if (weakCriticalAxes.length === 0) {
    77→      return {
    78→        recommendation: 'PARK',
    79→        reasons: [
    80→          `Score global (${globalScore}) dans la plage [${DECISION_THRESHOLDS.PARK_MIN}, ${DECISION_THRESHOLDS.PARK_MAX}[`,
    81→          'Aucun blocking gap ni axe critique sous seuil',
    82→        ],
    83→      };
    84→    }
    85→    // Si axes critiques < 25, on tombe en KILL (conflit → règle la plus restrictive)
    86→    return {
    87→      recommendation: 'KILL',
    88→      reasons: [
    89→        `Score global (${globalScore}) dans plage PARK mais axes critiques faibles : ${weakCriticalAxes.map((a) => `${a.axis}=${a.score}`).join(', ')}`,
    90→      ],
    91→    };
    92→  }
    93→
    94→  // ─── Règle 4 : GO (testée avant EXPLORE pour la logique score >= 70) ──
    95→  if (globalScore >= DECISION_THRESHOLDS.GO_MIN) {
    96→    // GO nécessite confidence >= MEDIUM
    97→    if (confidenceLevel === 'LOW') {
    98→      return {
    99→        recommendation: 'EXPLORE',
   100→        reasons: [
   101→          `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN} mais confidence LOW`,
   102→        ],
   103→      };
   104→    }
   105→
   106→    // GO nécessite aucun blocking_gap
   107→    if (blockingAxes.length > 0) {
   108→      // Déjà géré par KILL, mais par sécurité
   109→      return {
   110→        recommendation: 'KILL',
   111→        reasons: [`Blocking gap malgré score élevé (${globalScore})`],
   112→      };
   113→    }
   114→
   115→    // GO nécessite tous les axes critiques >= 50
   116→    const weakCriticalAxes = getCriticalAxesBelowThreshold(
   117→      analysis,
   118→      DECISION_THRESHOLDS.GO_CRITICAL_MIN
   119→    );
   120→    if (weakCriticalAxes.length > 0) {
   121→      return {
   122→        recommendation: 'EXPLORE',
   123→        reasons: [
   124→          `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN} mais axes critiques faibles : ${weakCriticalAxes.map((a) => `${a.axis}=${a.score}`).join(', ')}`,
   125→        ],
   126→      };
   127→    }
   128→
   129→    return {
   130→      recommendation: 'GO',
   131→      reasons: [
   132→        `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN}`,
   133→        `Confidence ${confidenceLevel} >= MEDIUM`,
   134→        'Aucun blocking gap, tous axes critiques >= 50',
   135→      ],
   136→    };
   137→  }
   138→
   139→  // ─── Règle 3 : EXPLORE ───────────────────────────────────────
   140→  if (
   141→    globalScore >= DECISION_THRESHOLDS.EXPLORE_MIN &&
   142→    globalScore < DECISION_THRESHOLDS.EXPLORE_MAX
   143→  ) {
   144→    return {
   145→      recommendation: 'EXPLORE',
   146→      reasons: [
   147→        `Score global (${globalScore}) dans la plage [${DECISION_THRESHOLDS.EXPLORE_MIN}, ${DECISION_THRESHOLDS.EXPLORE_MAX}[`,
   148→      ],
   149→    };
   150→  }
   151→
   152→  // ─── Fallback : PARK (score < 30 déjà géré par KILL) ─────────
   153→  return {
   154→    recommendation: 'PARK',
   155→    reasons: [`Score global (${globalScore}) — cas résiduel`],
   156→  };
   157→}
   158→
   159→// ═══════════════════════════════════════════════════════════════════
   160→// HELPERS
   161→// ═══════════════════════════════════════════════════════════════════
   162→
   163→function getBlockingGapAxes(analysis: AnalysisAxes): AnalysisAxis[] {
   164→  const axes: AnalysisAxis[] = [];
   165→  for (const [key, value] of Object.entries(analysis)) {
   166→    if (value.blocking_gap) {
   167→      axes.push(key as AnalysisAxis);
   168→    }
   169→  }
   170→  return axes;
   171→}
   172→
   173→function getCriticalAxesBelowThreshold(
   174→  analysis: AnalysisAxes,
   175→  threshold: number
   176→): Array<{ axis: AnalysisAxis; score: number }> {
   177→  const weak: Array<{ axis: AnalysisAxis; score: number }> = [];
   178→  for (const axis of CRITICAL_AXES) {
   179→    if (analysis[axis].score < threshold) {
   180→      weak.push({ axis, score: analysis[axis].score });
   181→    }
   182→  }
   183→  return weak;
   184→}
   185→

